        {"numero": "243", "descricao": "Questão referente à taxa SELIC como índice de correção de tributos pagos indevidamente.", "tese": "A taxa SELIC é legítima como índice de correção monetária e de juros de mora na repetição de indébito tributário.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "255", "descricao": "Questão referente ao creditamento de IPI sobre insumos tributados quando o produto final é isento.", "tese": "Não há direito a creditamento de IPI em relação a insumos tributados quando o produto final é isento ou sujeito à alíquota zero.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "280", "descricao": "Questão referente à inclusão de verbas indenizatórias na base de cálculo da contribuição ao FGTS.", "tese": "As parcelas de natureza indenizatória não compõem a base de cálculo da contribuição ao FGTS.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "305", "descricao": "Questão referente à decadência para lançamento de contribuição previdenciária.", "tese": "A decadência do direito de a Fazenda Pública constituir o crédito tributário referente a contribuições previdenciárias segue o art. 173, I, do CTN.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "322", "descricao": "Questão referente à legitimidade passiva para restituição de tributo indireto.", "tese": "O contribuinte de direito é parte legítima para pleitear a restituição do tributo indireto, desde que comprove ter assumido o encargo financeiro ou que tenha autorização do contribuinte de fato.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "361", "descricao": "Questão referente à isenção de imposto de renda sobre aposentadoria por moléstia grave.", "tese": "A isenção do imposto de renda prevista no art. 6º, XIV, da Lei 7.713/1988 aplica-se aos proventos de aposentadoria ou reforma dos portadores de moléstia grave, independentemente de sintomas atuais.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "396", "descricao": "Questão referente à incidência de IRPF sobre complementação de aposentadoria.", "tese": "É indevida a cobrança de imposto de renda sobre o valor de complementação de aposentadoria, na proporção das contribuições efetuadas exclusivamente pelo beneficiário sob a vigência da Lei 7.713/1988.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "434", "descricao": "Questão referente ao creditamento de PIS/COFINS sobre despesas com frete.", "tese": "As despesas com frete na aquisição de insumos geram direito a créditos de PIS e COFINS no regime não cumulativo.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "456", "descricao": "Questão referente à base de cálculo do IRPJ e CSLL sobre incentivos fiscais de ICMS.", "tese": "Os incentivos fiscais de ICMS concedidos pelos Estados não compõem a base de cálculo do IRPJ e da CSLL, desde que observados os requisitos do art. 30 da Lei 12.973/2014.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "490", "descricao": "Questão referente à multa tributária e princípio do não confisco.", "tese": "A multa tributária qualificada em razão de sonegação, fraude ou conluio pode ser fixada no percentual de 150% sem que isso configure confisco.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "525", "descricao": "Questão referente à exclusão do PIS e COFINS da própria base de cálculo.", "tese": "As contribuições ao PIS e à COFINS não podem compor a sua própria base de cálculo.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "537", "descricao": "Questão referente à responsabilidade tributária de sócio-gerente.", "tese": "A mera inadimplência tributária não configura infração à lei apta a ensejar a responsabilidade pessoal do sócio-gerente prevista no art. 135, III, do CTN.", "situacao": "transitado", "area": "direito tributário"},
        {"numero": "573", "descricao": "Questão referente à prescrição para cobrança de créditos não tributários.", "tese": "O prazo de prescrição para cobrança de créditos não tributários da Fazenda Pública é de cinco anos, nos termos do Decreto 20.910/1932.", "situacao": "transitado", "area": "direito tributário"},

        # DIREITO DO CONSUMIDOR
        {"numero": "26", "descricao": "Questão referente à responsabilidade civil das instituições financeiras por fraudes praticadas por terceiros.", "tese": "As instituições financeiras respondem objetivamente pelos danos gerados por fortuito interno relativo a fraudes e delitos praticados por terceiros no âmbito de operações bancárias.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "54", "descricao": "Questão referente à capitalização de juros em contratos bancários.", "tese": "É permitida a capitalização de juros com periodicidade inferior a um ano em contratos celebrados após 31/03/2000, data da publicação da MP 1.963-17/2000.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "95", "descricao": "Questão referente à responsabilidade do fornecedor por vício de qualidade do produto.", "tese": "O fornecedor responde solidariamente pelos vícios de qualidade ou quantidade que tornem os produtos impróprios ou inadequados ao consumo.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "232", "descricao": "Questão referente ao abusividade da venda casada.", "tese": "Constitui venda casada a exigência de contratação de seguro como condição para concessão de financiamento.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "271", "descricao": "Questão referente à cobrança de tarifa de liquidação antecipada.", "tese": "É abusiva a cláusula contratual que prevê cobrança de tarifa de liquidação antecipada de financiamento de veículo.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "299", "descricao": "Questão referente ao prazo prescricional para ações de repetição de indébito em contratos bancários.", "tese": "Na ação de repetição de indébito relativa a contrato bancário, prescreve em três anos a pretensão de ressarcimento dos valores indevidamente cobrados.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "335", "descricao": "Questão referente à inversão do ônus da prova em relações de consumo.", "tese": "A inversão do ônus da prova prevista no art. 6º, VIII, do CDC é regra de instrução, devendo a decisão ser proferida preferencialmente na fase de saneamento do processo.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "378", "descricao": "Questão referente à validade da cláusula-mandato em contratos bancários.", "tese": "A cláusula-mandato inserida em contrato de cartão de crédito é nula quando utilizada para emissão de títulos de crédito pelo mandatário em prejuízo do consumidor.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "399", "descricao": "Questão referente à devolução em dobro de cobranças indevidas.", "tese": "A restituição em dobro do indébito, prevista no parágrafo único do art. 42 do CDC, independe da natureza do elemento volitivo do fornecedor que cobrou indevidamente.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "422", "descricao": "Questão referente à abusividade de cláusula de reajuste em planos de saúde por faixa etária.", "tese": "É válida a cláusula contratual de reajuste por mudança de faixa etária em planos de saúde, desde que haja previsão contratual e não sejam aplicados percentuais desarrazoados.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "455", "descricao": "Questão referente à responsabilidade do banco por inscrição indevida em cadastro restritivo.", "tese": "A inscrição indevida do nome do consumidor em cadastro de inadimplentes configura dano moral in re ipsa.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "487", "descricao": "Questão referente à prescrição em ação de cobrança de seguro DPVAT.", "tese": "Prescreve em três anos a pretensão do segurado contra o segurador, contados da ciência inequívoca da incapacidade.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "528", "descricao": "Questão referente ao dever de informação em planos de saúde.", "tese": "É abusiva a negativa de cobertura por plano de saúde sem comunicação prévia ao consumidor sobre as exclusões contratuais.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "568", "descricao": "Questão referente à limitação de juros em cédula de crédito rural.", "tese": "Nos contratos de crédito rural, os juros remuneratórios não estão limitados a 12% ao ano.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "610", "descricao": "Questão referente ao prazo prescricional em ação de indenização por dano moral.", "tese": "O prazo prescricional da pretensão indenizatória decorrente de inscrição indevida em cadastro restritivo é de três anos, nos termos do art. 206, §3º, V, do CC.", "situacao": "transitado", "area": "direito do consumidor"},
        {"numero": "735", "descricao": "Questão referente à responsabilidade das companhias aéreas por extravio de bagagem.", "tese": "É aplicável o Código de Defesa do Consumidor às relações jurídicas entre passageiros e companhias aéreas, prevalecendo sobre a Convenção de Montreal no tocante à indenização por danos morais.", "situacao": "transitado", "area": "direito do consumidor"},

        # DIREITO ADMINISTRATIVO
        {"numero": "163", "descricao": "Questão referente à acumulação de auxílio-acidente com aposentadoria.", "tese": "É possível a acumulação de auxílio-acidente com aposentadoria quando a lesão incapacitante e a concessão da aposentadoria forem anteriores à vigência da Lei 9.528/1997.", "situacao": "transitado", "area": "direito administrativo"},
        {"numero": "251", "descricao": "Questão referente à possibilidade de reenquadramento funcional por via judicial.", "tese": "O Poder Judiciário não pode, sob pena de violação ao princípio da separação dos poderes, determinar reenquadramento funcional de servidor público.", "situacao": "transitado", "area": "direito administrativo"},
