        {"numero": "347", "descricao": "Questão referente à concessão de aposentadoria especial a servidor público.", "tese": "Aplica-se o art. 57, §1º, da Lei 8.213/1991 ao servidor público até que lei complementar discipline a matéria.", "situacao": "transitado", "area": "direito administrativo"},
