        {"numero": "493", "descricao": "Questão referente à devolutividade do recurso especial em matéria de improbidade administrativa.", "tese": "O recurso especial em ação de improbidade administrativa permite o reexame das sanções aplicadas, desde que não implique revolvimento de fatos e provas.", "situacao": "transitado", "area": "direito administrativo"},
