        {"numero": "672", "descricao": "Questão referente à responsabilidade dos gestores por atos praticados em licitações.", "tese": "A responsabilidade pessoal do gestor público por irregularidades em licitação depende da demonstração de dolo ou culpa.", "situacao": "transitado", "area": "direito administrativo"},
        {"numero": "743", "descricao": "Questão referente à prescrição para ação de ressarcimento por dano ao erário.", "tese": "É prescritível a ação de reparação de danos à Fazenda Pública decorrente de ilícito civil, aplicando-se o prazo quinquenal.", "situacao": "transitado", "area": "direito administrativo"},
        {"numero": "792", "descricao": "Questão referente ao direito de servidor público a licença para acompanhar cônjuge.", "tese": "O servidor público federal tem direito a licença para acompanhar cônjuge que foi deslocado para outro ponto do território nacional, nos termos do art. 84 da Lei 8.112/1990.", "situacao": "transitado", "area": "direito administrativo"},

